   * ```
   * GET /api/v1/products?categoryId=cat_123&isActive=true&include=variants,modifiers
   *
   * Response:
   * {
   *   "success": true,
   *   "data": [...],
   *   "meta": { "page": 1, "perPage": 20, "total": 50, "totalPages": 3 }
   * }
   * ```
   */
  @Get('/')
  @Authorized('menu.view')
  async list(
    @CurrentOrg() org: TenantOrganization,
    @QueryParams() query: ListProductsQuery
  ): Promise<PaginatedApiResponse<Product>> {
    const result = await this.productService.list(org.id, query);
    return this.paginated(result);
  }

